const http = require('http');
const WebSocket = require('ws');
const { randomUUID } = require('crypto');

const PORT = process.env.PORT || 8080;
const TICK_RATE = 20;
const MAP_WIDTH = 2000;
const MAP_HEIGHT = 2000;
const PLAYER_START_RESOURCES = 1000;
const UNIT_SPEED = 120;
const UNIT_ATTACK_RANGE = 60;
const UNIT_ATTACK_DAMAGE = 10;
const UNIT_ATTACK_COOLDOWN = 0.5;
const BUILDING_SIZE = 40;
const UNIT_SIZE = 16;

const UNIT_TYPES = {
  worker: {
    hp: 50,
    speed: 100,
    attackDamage: 4,
    attackRange: 25,
    attackCooldown: 0.8,
    cost: 50,
  },
  soldier: {
    hp: 100,
    speed: 120,
    attackDamage: 12,
    attackRange: 60,
    attackCooldown: 0.5,
    cost: 100,
  },
  tank: {
    hp: 250,
    speed: 70,
    attackDamage: 30,
    attackRange: 110,
    attackCooldown: 1.2,
    cost: 250,
  },
};

const BUILDING_TYPES = {
  base: {
    hp: 1000,
    cost: 0,
    size: 60,
  },
  barracks: {
    hp: 500,
    cost: 200,
    size: 50,
  },
  turret: {
    hp: 300,
    cost: 150,
    size: 35,
    attackDamage: 15,
    attackRange: 140,
    attackCooldown: 0.7,
  },
};

const server = http.createServer();
const wss = new WebSocket.Server({ server });

const state = {
  players: new Map(),
  units: new Map(),
  buildings: new Map(),
  sockets: new Map(),
  lastTick: Date.now(),
};

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function distance(a, b) {
  const dx = a.x - b.x;
  const dy = a.y - b.y;
  return Math.sqrt(dx * dx + dy * dy);
}

function nowSeconds() {
  return Date.now() / 1000;
}

function serializeUnit(unit) {
  return {
    id: unit.id,
    ownerId: unit.ownerId,
    type: unit.type,
    x: unit.x,
    y: unit.y,
    hp: unit.hp,
    maxHp: unit.maxHp,
    target: unit.target,
    attackTargetId: unit.attackTargetId,
  };
}

function serializeBuilding(building) {
  return {
    id: building.id,
    ownerId: building.ownerId,
    type: building.type,
    x: building.x,
    y: building.y,
    hp: building.hp,
    maxHp: building.maxHp,
    size: building.size,
  };
}

function serializePlayer(player) {
  return {
    id: player.id,
    name: player.name,
    resources: player.resources,
  };
}

function broadcast(message) {
  const payload = JSON.stringify(message);
  for (const ws of state.sockets.values()) {
    if (ws.readyState === WebSocket.OPEN) {
      ws.send(payload);
    }
  }
}

function send(ws, message) {
  if (ws.readyState === WebSocket.OPEN) {
    ws.send(JSON.stringify(message));
  }
}

function createPlayer(ws, name = 'Player') {
  const id = randomUUID();
  const player = {
    id,
    name,
    resources: PLAYER_START_RESOURCES,
    socketId: id,
  };
  state.players.set(id, player);
  state.sockets.set(id, ws);

  const base = createBuilding(id, 'base', randSpawn(), randSpawn());
  createUnit(id, 'worker', base.x + 80, base.y);
  createUnit(id, 'worker', base.x + 100, base.y + 20);
  createUnit(id, 'soldier', base.x + 60, base.y + 60);

  return player;
}

function randSpawn() {
  return Math.floor(Math.random() * 1600) + 200;
}

function createUnit(ownerId, type, x, y) {
  const def = UNIT_TYPES[type];
  if (!def) return null;

  const unit = {
    id: randomUUID(),
    ownerId,
    type,
    x: clamp(x, 0, MAP_WIDTH),
    y: clamp(y, 0, MAP_HEIGHT),
    hp: def.hp,
    maxHp: def.hp,
    speed: def.speed || UNIT_SPEED,
    attackDamage: def.attackDamage || UNIT_ATTACK_DAMAGE,
    attackRange: def.attackRange || UNIT_ATTACK_RANGE,
    attackCooldown: def.attackCooldown || UNIT_ATTACK_COOLDOWN,
    lastAttackAt: 0,
    target: null,
    attackTargetId: null,
  };

  state.units.set(unit.id, unit);
  return unit;
}

function createBuilding(ownerId, type, x, y) {
  const def = BUILDING_TYPES[type];
  if (!def) return null;

  const building = {
    id: randomUUID(),
    ownerId,
    type,
    x: clamp(x, 0, MAP_WIDTH),
    y: clamp(y, 0, MAP_HEIGHT),
    hp: def.hp,
    maxHp: def.hp,
    size: def.size || BUILDING_SIZE,
    attackDamage: def.attackDamage || 0,
    attackRange: def.attackRange || 0,
    attackCooldown: def.attackCooldown || 0,
    lastAttackAt: 0,
  };

  state.buildings.set(building.id, building);
  return building;
}

function getEntity(entityId) {
  return state.units.get(entityId) || state.buildings.get(entityId) || null;
}

function removeEntity(entityId) {
  if (state.units.delete(entityId)) {
    broadcast({ type: 'entityRemoved', entityType: 'unit', id: entityId });
    return;
  }
  if (state.buildings.delete(entityId)) {
    broadcast({ type: 'entityRemoved', entityType: 'building', id: entityId });
  }
}

function processMoveCommand(playerId, data) {
  const { unitIds, x, y } = data;
  if (!Array.isArray(unitIds) || typeof x !== 'number' || typeof y !== 'number') return;

  const tx = clamp(x, 0, MAP_WIDTH);
  const ty = clamp(y, 0, MAP_HEIGHT);

  for (const unitId of unitIds) {
    const unit = state.units.get(unitId);
    if (!unit || unit.ownerId !== playerId) continue;
    unit.target = { x: tx, y: ty };
    unit.attackTargetId = null;
  }

  broadcast({
    type: 'commandProcessed',
    command: 'move',
    playerId,
    unitIds,
    x: tx,
    y: ty,
  });
}

function processAttackCommand(playerId, data) {
  const { unitIds, targetId } = data;
  if (!Array.isArray(unitIds) || typeof targetId !== 'string') return;

  const target = getEntity(targetId);
  if (!target || target.ownerId === playerId) return;

  for (const unitId of unitIds) {
    const unit = state.units.get(unitId);
    if (!unit || unit.ownerId !== playerId) continue;
    unit.attackTargetId = targetId;
    unit.target = null;
  }

  broadcast({
    type: 'commandProcessed',
    command: 'attack',
    playerId,
    unitIds,
    targetId,
  });
}

function processBuildCommand(playerId, data) {
  const { buildingType, x, y, unitType } = data;
  const player = state.players.get(playerId);
  if (!player) return;

  if (buildingType) {
    const def = BUILDING_TYPES[buildingType];
    if (!def) return;
    if (player.resources < def.cost) return;

    player.resources -= def.cost;
    const building = createBuilding(playerId, buildingType, x, y);
    if (!building) return;

    broadcast({
      type: 'buildingCreated',
      building: serializeBuilding(building),
      player: serializePlayer(player),
    });
    return;
  }

  if (unitType) {
    const def = UNIT_TYPES[unitType];
    if (!def) return;
    if (player.resources < def.cost) return;

    const base = [...state.buildings.values()].find(b => b.ownerId === playerId && b.type === 'base');
    if (!base) return;

    player.resources -= def.cost;
    const unit = createUnit(playerId, unitType, base.x + Math.random() * 60 - 30, base.y + Math.random() * 60 - 30);
    if (!unit) return;

    broadcast({
      type: 'unitCreated',
      unit: serializeUnit(unit),
      player: serializePlayer(player),
    });
  }
}

function dealDamage(attacker, target) {
  target.hp -= attacker.attackDamage;
  if (target.hp <= 0) {
    removeEntity(target.id);
  } else {
    broadcast({
      type: 'entityDamaged',
      id: target.id,
      hp: target.hp,
      entityType: state.units.has(target.id) ? 'unit' : 'building',
    });
  }
}

function updateUnit(unit, dt) {
  if (unit.attackTargetId) {
    const target = getEntity(unit.attackTargetId);
    if (!target || target.ownerId === unit.ownerId) {
      unit.attackTargetId = null;
    } else {
      const d = distance(unit, target);
      if (d <= unit.attackRange) {
        const t = nowSeconds();
        if (t - unit.lastAttackAt >= unit.attackCooldown) {
          unit.lastAttackAt = t;
          dealDamage(unit, target);
        }
      } else {
        const dx = target.x - unit.x;
        const dy = target.y - unit.y;
        const len = Math.sqrt(dx * dx + dy * dy) || 1;
        const step = unit.speed * dt;
        if (step >= d) {
          unit.x = target.x;
          unit.y = target.y;
        } else {
          unit.x += (dx / len) * step;
          unit.y += (dy / len) * step;
        }
      }
      return;
    }
  }

  if (unit.target) {
    const dx = unit.target.x - unit.x;
    const dy = unit.target.y - unit.y;
    const d = Math.sqrt(dx * dx + dy * dy);
    if (d < 1) {
      unit.x = unit.target.x;
      unit.y = unit.target.y;
      unit.target = null;
      return;
    }

    const step = unit.speed * dt;
    if (step >= d) {
      unit.x = unit.target.x;
      unit.y = unit.target.y;
      unit.target = null;
    } else {
      unit.x += (dx / d) * step;
      unit.y += (dy / d) * step;
    }
  }
}

function updateBuilding(building) {
  if (!building.attackRange || !building.attackDamage) return;

  let nearest = null;
  let nearestDist = Infinity;

  for (const unit of state.units.values()) {
    if (unit.ownerId === building.ownerId) continue;
    const d = distance(building, unit);
    if (d <= building.attackRange && d < nearestDist) {
      nearest = unit;
      nearestDist = d;
    }
  }

  if (!nearest) return;

  const t = nowSeconds();
  if (t - building.lastAttackAt >= building.attackCooldown) {
    building.lastAttackAt = t;
    dealDamage(building, nearest);
  }
}

function gameLoop() {
  const now = Date.now();
  const dt = Math.min((now - state.lastTick) / 1000, 0.1);
  state.lastTick = now;

  for (const unit of state.units.values()) {
    updateUnit(unit, dt);
  }

  for (const building of state.buildings.values()) {
    updateBuilding(building);
  }

  broadcast({
    type: 'state',
    players: [...state.players.values()].map(serializePlayer),
    units: [...state.units.values()].map(serializeUnit),
    buildings: [...state.buildings.values()].map(serializeBuilding),
    serverTime: now,
  });
}

function fullStateForPlayer(player) {
  return {
    type: 'welcome',
    playerId: player.id,
    map: {
      width: MAP_WIDTH,
      height: MAP_HEIGHT,
    },
    players: [...state.players.values()].map(serializePlayer),
    units: [...state.units.values()].map(serializeUnit),
    buildings: [...state.buildings.values()].map(serializeBuilding),
  };
}

function handleMessage(ws, playerId, raw) {
  let msg;
  try {
    msg = JSON.parse(raw.toString());
  } catch {
    send(ws, { type: 'error', message: 'Invalid JSON' });
    return;
  }

  if (!msg || typeof msg.type !== 'string') {
    send(ws, { type: 'error', message: 'Invalid message format' });
    return;
  }

  switch (msg.type) {
    case 'move':
      processMoveCommand(playerId, msg);
      break;
    case 'attack':
      processAttackCommand(playerId, msg);
      break;
    case 'build':
      processBuildCommand(playerId, msg);
      break;
    case 'setName': {
      const player = state.players.get(playerId);
      if (!player) return;
      if (typeof msg.name === 'string' && msg.name.trim()) {
        player.name = msg.name.trim().slice(0, 24);
        broadcast({ type: 'playerUpdated', player: serializePlayer(player) });
      }
      break;
    }
    case 'ping':
      send(ws, { type: 'pong', serverTime: Date.now() });
      break;
    default:
      send(ws, { type: 'error', message: `Unknown message type: ${msg.type}` });
  }
}

wss.on('connection', ws => {
  const player = createPlayer(ws);

  send(ws, fullStateForPlayer(player));

  broadcast({
    type: 'playerJoined',
    player: serializePlayer(player),
  });

  for (const building of state.buildings.values()) {
    if (building.ownerId === player.id) {
      broadcast({ type: 'buildingCreated', building: serializeBuilding(building), player: serializePlayer(player) });
    }
  }

  for (const unit of state.units.values()) {
    if (unit.ownerId === player.id) {
      broadcast({ type: 'unitCreated', unit: serializeUnit(unit), player: serializePlayer(player) });
    }
  }

  ws.on('message', data => handleMessage(ws, player.id, data));

  ws.on('close', () => {
    state.sockets.delete(player.id);
    state.players.delete(player.id);

    for (const unit of [...state.units.values()]) {
      if (unit.ownerId === player.id) removeEntity(unit.id);
    }

    for (const building of [...state.buildings.values()]) {
      if (building.ownerId === player.id) removeEntity(building.id);
    }

    broadcast({
      type: 'playerLeft',
      playerId: player.id,
    });
  });

  ws.on('error', () => {});
});

setInterval(gameLoop, 1000 / TICK_RATE);

server.listen(PORT, () => {
  console.log(`RTS WebSocket server listening on port ${PORT}`);
});